<!-- DynamicTablePage.vue -->
<template>
  <v-app>
    <v-app-bar color="white" dark>
      <v-toolbar-title>Dynamic Tables</v-toolbar-title>
    </v-app-bar>

    <v-main>
      <v-container fluid>
        <!-- Loop through each table in the parsed data -->
        <v-row
          v-for="(table, tableIndex) in tables"
          :key="tableIndex"
          class="table-section"
        >
          <v-col cols="12">
            <v-card outlined>
              <v-card-title>
                {{ formatTableName(table.name) }}
                <v-btn
                  v-if="table.hyperlink"
                  icon
                  @click="navigateTo(table.hyperlink.url)"
                  :title="table.hyperlink.label"
                  class="table-hyperlink-button"
                >
                  <v-icon>mdi-link</v-icon>
                </v-btn>
              </v-card-title>

              <!-- Table with headers and rows -->
              <v-simple-table>
                  <tbody>
                    <tr v-for="(row, rowIndex) in table.rows" :key="rowIndex">
                      <td
                        v-for="(cell, colIndex) in row"
                        :key="colIndex"
                        :colspan="cell ? cell.colspan : 1"
                        :rowspan="cell ? cell.rowspan : 1"
                      >
                        <template v-if="cell">
                          <!-- Render input field if cell has a placeholder, else display value -->
                          <v-text-field
                            v-if="cell.isPlaceholder"
                            v-model="cell.value"
                            :label="cell.id"
                            variant="outlined"
                            dense
                            class="table-cell-input"
                            hide-details
                          />
                          <span v-else>{{ cell.content }}</span>
                        </template>
                        <template v-else>
                          <!-- Empty cell -->
                          &nbsp;
                        </template>
                      </td>
                    </tr>
                  </tbody>
                </v-simple-table>
              </v-card>
            </v-col>
          </v-row>

        <!-- Submit Button -->
        <v-btn @click="navigateToCheckboxPage" color="primary" class="mt-4">
          Next
        </v-btn>
      </v-container>
    </v-main>
  </v-app>
</template>

<script>
import { ref, onMounted } from 'vue';
import { useStore } from 'vuex';
import { useRouter, onBeforeRouteLeave } from 'vue-router';
import { fetchAndParseTables } from '@/utils/utility.js';
import axios from 'axios';

export default {
  setup() {
    const store = useStore();
    const router = useRouter();
    const tables = ref([]);

    /**
     * Optional function to log cell updates
     * Can be expanded to perform additional actions on input
     * @param {Object} cell - The cell object being updated
     */
    const logCellUpdate = (cell) => {
      console.log(`Cell updated: ${cell.id} = ${cell.value}`);
      // Optionally, persist the updated cell value to Vuex or perform validation
    };

    /**
     * Load persisted table values from Vuex store
     */
    const loadPersistedTableValues = () => {
      console.log("Loading persisted structured table from Vuex...");
      tables.value = store.state.structuredTableData || [];
    };

    /**
     * Fetch and parse tables from the document template
     */
    const loadDynamicTables = async () => {
      const selectedTemplate = store.state.selectedTemplate;

      if (!selectedTemplate || !selectedTemplate.fileId || !selectedTemplate.bucketName) {
        alert("No valid template selected. Please go back and select a template.");
        router.push({ name: "userOptionsPage" });
        return;
      }

      const { fileId, bucketName } = selectedTemplate;
      const hasPersistedData = store.state.structuredTableData.length > 0;

      if (!store.state.isNavigatingBack || !hasPersistedData) {
        console.log("Fetching template data for tables...");
        try {
          // Fetch template data using the new endpoint
          const response = await axios.get('/api/files/fetch-template-content', {
            params: {
              fileId,
              bucketName,
            },
            responseType: 'arraybuffer', // Handle binary data
          });

          console.log("Fetched template file successfully:", response);

          // Parse tables from the fetched document
          const { parsedTables } = await fetchAndParseTables(response.data);

          // Set parsed tables to the component state
          tables.value = parsedTables;
          console.log("Template tables loaded:", tables.value);

          // Commit parsed tables to Vuex for persistence
          store.dispatch('saveStructuredTableData', parsedTables);
          console.log("Structured table data saved to Vuex:", parsedTables);
        } catch (error) {
          console.error("Error fetching or parsing template data:", error);
          alert("Failed to load dynamic table data. Please try again later.");
        }
      } else {
        console.log("Navigating back: Loading persisted structured table data...");
        loadPersistedTableValues();
      }

      store.commit("setNavigatingBack", false);
    };

    /**
     * Build the final data object for Docxtemplater
     * @returns {Object} - The data object mapping placeholder IDs to user inputs
     */
    const buildDocxtemplaterData = () => {
      console.log('Starting to build data object from table:', tables.value);
      const dataForDocxtemplater = {};

      // Loop through each table to gather data
      tables.value.forEach((table) => {
        table.rows.forEach((row) => {
          row.forEach((cell) => {
            if (cell.isPlaceholder && cell.id) {
              // Map the placeholder ID to the user-entered value
              dataForDocxtemplater[cell.id] = cell.value;
            }
          });
        });
      });

      console.log('Data for Docxtemplater:', dataForDocxtemplater);
      return dataForDocxtemplater;
    };

    /**
     * Navigate to CheckboxPage.vue after collecting data
     */
    const navigateToCheckboxPage = () => {
      const docxtemplaterData = buildDocxtemplaterData();

      store.dispatch("saveTableData", docxtemplaterData); // Flattened data for Docxtemplater
      // Optionally, if you need to save structured data separately:
      // store.dispatch("saveStructuredTableData", tables.value);

      console.log("Saved table data to Vuex:", docxtemplaterData);
      router.push({ name: "checkboxPage" });
    };

    /**
     * Format the table name for display (e.g., "table_name" to "Table Name")
     * @param {String} name - The original table name
     * @returns {String} - The formatted table name
     */
    const formatTableName = (name) => {
      return name
        .replace(/_/g, ' ')
        .replace(/\b\w/g, (c) => c.toUpperCase());
    };

    /**
     * Open a hyperlink in a new browser tab
     * @param {String} url - The URL to navigate to
     */
    const navigateTo = (url) => {
      window.open(url, '_blank'); // Opens the link in a new tab
    };

    onMounted(() => {
      loadDynamicTables();
    });

    onBeforeRouteLeave((to, from, next) => {
      store.commit('setNavigatingBack', true); // Set isNavigatingBack to true when navigating away
      next(); // Allow the navigation to proceed
    });

    return {
      tables,
      navigateTo,
      navigateToCheckboxPage,
      formatTableName,
      logCellUpdate,
    };
  },
};
</script>

<style scoped>
.table-section {
  margin-bottom: 24px;
}

.v-card {
  margin: 16px;
  padding-bottom: 16px; /* Add padding to the bottom of the card */
}

/* Add padding, alignment, and border to table headers */
th {
  padding: 8px 12px;
  white-space: normal;
  text-align: center;
  font-weight: bold;
  border: 1px solid #ccc; /* Add border to the header cells */
  border-top-left-radius: 2px; /* Optional: round the top left corner */
  border-top-right-radius: 2px; /* Optional: round the top right corner */
  background-color: rgba(15, 101, 84, 0.644); /* Add a light background color for contrast */
}

/* Add padding, border, and row shading to table cells */
td {
  padding: 8px 12px;
  border: 1px solid #ccc;
  border-radius: 1px;
}

tr:nth-child(even) {
  background-color: #f9f9f9;
}

/* Adjust the text input width and add margin */
.table-cell-input {
  width: 100%;
}

.table-cell-input .v-input__control {
  border: none !important; /* Remove the border */
  box-shadow: none !important; /* Remove any shadow */
  padding: 0 !important; /* Minimize padding */
}

.table-cell-input input {
  border: none !important; /* Remove input border */
  box-shadow: none !important; /* Remove input shadow */
  padding: 0 !important; /* Minimize input padding */
  font-size: 14px; /* Adjust font size */
  background-color: transparent !important; /* Make background transparent */
}

.table-cell-input .v-input__slot {
  border-radius: 0 !important; /* Remove any border-radius */
}

.v-simple-table {
  border-radius: 8px;
  overflow: hidden;
}
</style>
